20	// Runes and moonstones are "components" — a distinct pricing tier that shares
21	// one base premium (and, later, block/alike rules). Naming the shared value
22	// makes the equality intentional rather than a coincidence two entries happen
23	// to share.
24	const COMPONENT_BASE_PREMIUM = 25;
25	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
26	// A "building block" of exactly this many alike components is offered at a
27	// special block premium instead of the per-component price.
28	const COMPONENT_BLOCK_SIZE = 3;
29	const COMPONENT_BLOCK_PREMIUM = 60;
30	
31	const BASE_PREMIUMS: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: COMPONENT_BASE_PREMIUM,
37	  moonstone: COMPONENT_BASE_PREMIUM,
38	};
39	const PROCESSING_FEE = 5;
40	
41	// Surcharges are expressed as integer percentages and applied as
42	// `amount * percent / 100`, keeping the maths in integers (avoids float errors
43	// such as `100 * 1.1 === 100.00000000000001`).
44	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
45	const CURSE_SURCHARGE_PERCENT = 50;
46	
47	const percentOf = (amount: number, percent: number): number =>
48	  (amount * percent) / 100;
49	
50	const itemBasePremium = (item: Item): number =>
51	  COMPONENT_TYPES.has(item.type)
52	    ? COMPONENT_BASE_PREMIUM
53	    : (BASE_PREMIUMS[item.type] ?? 0);
54	
55	// Item-specific surcharge: a curse adds 50% of that item's own base premium.
56	const itemSurcharge = (item: Item): number =>
57	  item.cursed ? percentOf(itemBasePremium(item), CURSE_SURCHARGE_PERCENT) : 0;
58	
59	const sumItemSurcharges = (items: Item[]): number =>
60	  items.reduce((total, item) => total + itemSurcharge(item), 0);
61	
62	const countByType = (items: Item[]): Map<string, number> => {
63	  const counts = new Map<string, number>();
64	  for (const item of items) {
65	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
66	  }
67	  return counts;
68	};
69	
70	const componentGroupPremium = (count: number): number =>
71	  count === COMPONENT_BLOCK_SIZE
72	    ? COMPONENT_BLOCK_PREMIUM
73	    : count * COMPONENT_BASE_PREMIUM;
74	
75	const typeGroupPremium = (type: string, count: number): number =>
76	  COMPONENT_TYPES.has(type)
77	    ? componentGroupPremium(count)
78	    : count * (BASE_PREMIUMS[type] ?? 0);
79	
80	const sumBasePremiums = (items: Item[]): number =>
81	  [...countByType(items)].reduce(
82	    (total, [type, count]) => total + typeGroupPremium(type, count),
83	    0,
84	  );
85	
86	export const quote = (
87	  _customer: Customer,
88	  step: QuoteStep,
89	  _quoteIndex: number,
90	): QuoteResult => {
91	  const policyBase = sumBasePremiums(step.items);
92	  const itemSurcharges = sumItemSurcharges(step.items);
93	  const firstInsurance = percentOf(policyBase, FIRST_INSURANCE_SURCHARGE_PERCENT);
94	  const premium = Math.ceil(
95	    policyBase + itemSurcharges + firstInsurance + PROCESSING_FEE,
96	  );
97	  return { premium };
98	};
99	
100	export const claim = (): unknown => {
101	  return undefined;
102	};
