// A single item's base premium. BASE_PREMIUMS is the single source of truth
// for per-type base prices (components included), so a plain lookup suffices —
// block pricing is a group-level concern handled separately in sumBasePremiums.
const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;

